docker exec el34-attacker python3 - <<'PY'
# Mini harness implementation
class MiniHarness:
    def __init__(self):
        self.tools = {
            "read_log": lambda s: f"log[{s}]: 20 failed logins",
            "get_reputation": lambda ip: f"{ip}: malicious(92)",
            "block_ip": lambda ip: f"BLOCKED {ip}"}
        self.SAFE = {"read_log", "get_reputation"}
        self.RISKY = {"block_ip"}
        self.memory = []
    def call(self, name, arg, approved=False):
        if name in self.RISKY and not approved:
            self.memory.append((name, arg, "APPROVAL_REQUIRED"))
            return "APPROVAL_REQUIRED"
        if name not in self.tools:
            self.memory.append((name, arg, "UNKNOWN"))
            return "UNKNOWN_TOOL"
        out = self.tools[name](arg)
        self.memory.append((name, arg, "ok"))
        return out
h = MiniHarness()
print("tools:", list(h.tools))
print("safe:", h.SAFE, "risky:", h.RISKY)
built = len(h.tools) == 3 and bool(h.RISKY) and hasattr(h, "memory")
print("HARNESS_BUILT" if built else "INCOMPLETE")
PY

